#include <bits/stdc++.h>
using namespace std;
const int maxn=4e4+5;
#define int long long
int n,t,cnt,f[maxn],w[maxn],v[maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>t;
	for(int i=1,a,b,c; i<=n; i++) {
		cin>>a>>b>>c;
		for(int j=1; j<=c; j*=2) {
			v[++cnt]=j*a;
			w[cnt]=j*b;
			c-=j;
		}
		if(c) {
			v[++cnt]=a*c;
			w[cnt]=b*c;
		}
	}
	for(int i=1; i<=cnt; i++) {
		for(int j=t; j>=w[i]; j--) {
			f[j]=max(f[j],f[j-w[i]]+v[i]);
		}
	}
	cout<<f[t];
	return 0;
}
